qry:select.qry:xquery:
for $r in sql('
SELECT COUNT(TTA20_REGISTRO_FC.oi_registro_fc) as count FROM TTA20_REGISTRO_FC, PER02_PERSONAL_EMP, PER01_PERSONAL, ORG03_EMPRESAS JOIN TTA20_REGISTRO_FC.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal, PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa WHERE TTA20_REGISTRO_FC.l_aprob=1 AND TTA20_REGISTRO_FC.n_saldo > 0 AND TTA20_REGISTRO_FC.oi_personal_emp in ({%=string(#SOURCE:FILTRO/ROWS/ROW/@id) %}) {%? (#SOURCE:FILTRO/@fecha_vencimiento = '') {% %} {% AND TTA20_REGISTRO_FC.f_registro_fc >= {Datetime(#SOURCE:FILTRO/@fecha_vencimiento)} %} %}
')/ROWS/ROW
